PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>

SELECT ?doidLabel ?hpoaLabel WHERE {
  GRAPH <urn:doid> {
    ?disease a obo:DOID_N ;
             rdfs:label ?doidLabel .
  }
  GRAPH <urn:hpoa> {
    ?phenotype a hpoa:Disease ;
                rdfs:label ?hpoaLabel;
                hpoa:source_id ?sourceId .
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT ?synonymLabel WHERE {
  GRAPH <urn:doid> {
    obo:DOID_9351 oboInOwl:hasExactSynonym ?synonym .
    ?synonym rdfs:label ?synonymLabel .
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT ?subclass ?label WHERE {
  GRAPH <urn:doid> {
    ?subclass a obo:Class .
    rdfs:label(?subclass) "neoplasm"^^rdfs:label .
    ?subclass rdfs:subClassOf* neoplasm .
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX hpoa: <http://example.org/hpoa/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT ?label WHERE {
  GRAPH <urn:hpo> {
    obo:HP_0001166 rdfs:label ?label .
  }
}

PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT (COUNT(DISTINCT ?term) AS ?total) WHERE {
  GRAPH <urn:hpo> {
    ?term a owl:Class .
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>

SELECT ?doidLabel WHERE {
  GRAPH <urn:hpoa> {
    ?disease a hpoa:Disease ;
              hpoa:source_id "OMIM_143100" .
    OPTIONAL {
      ?doid a oboInOwl:Class ;
            oboInOwl:hasDbXref ?xref .
      FILTER(CONTAINS(LCASE(?xref), "mim"))
      BIND(REPLACE(STR(?xref), "^MIM:", "OMIM:") AS ?omim)
      rdfs:label ?doidLabel
    }
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX hpoa: <http://example.org/hpoa/>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
SELECT DISTINCT ?disease_name WHERE {
  GRAPH <urn:hpoa> {
    ?disease hpoa:has_phenotype obo:HP_0001250 ;
             rdfs:label ?disease_name .
  }
} LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT DISTINCT ?disease_name WHERE {
  GRAPH <urn:hpoa> {
    ?phenotype hpoa:has_phenotype obo:HP_0001166 ;
                rdfs:label ?disease_name .
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>

SELECT DISTINCT ?phenotype_label WHERE {
  GRAPH <urn:doid> {
    ?disease oboInOwl:id "DDOID_14323" ;
             oboInOwl:hasDbXref "MIM:154700" .
    ?disease oboInOwl:id "DDOID_13359" ;
             oboInOwl:hasDbXref "MIM:13359" .
  }

  GRAPH <urn:hpoa> {
    ?phenotype hpoa:source_id FILTER(CONTAINS(LCASE(?s), "marfan")) ;
            hpoa:has_phenotype ?disease .
    ?phenotype hpoa:source_id FILTER(CONTAINS(LCASE(?s), "ehlers-danlos")) ;
            hpoa:has_phenotype ?disease .
  }

  GRAPH <urn:hpo> {
    ?phenotype rdfs:label ?phenotype_label .
  }
}

PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX hpoa: <http://example.org/hpoa/>
PREFIX obo: <http://purl.obolibrary.org/obo/>
SELECT DISTINCT ?disease_name ?source_id WHERE {
  GRAPH <urn:doid> {
    ?disease oboInOwl:hasDbXref ?mim ;
             rdfs:label ?disease_name .
    FILTER(CONTAINS(LCASE(?disease_name), "intellectual disability"))
  }
} LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
PREFIX obo: <http://purl.obolibrary.org/obo/>

SELECT ?disease_label ?phenotype_label WHERE {
  GRAPH <urn:doid> {
    ?doid oboInOwl:hasDbXref "MIM:154700" ;
          rdfs:label ?disease_label .
  }
  GRAPH <urn:hpoa> {
    ?phenotype hpoa:has_phenotype ?doid;
                 rdfs:label ?phenotype_label .
    BIND(REPLACE(STR(?doid), "^MIM:", "OMIM:") AS ?doid_omim)
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>

SELECT ?diseaseLabel WHERE {
  GRAPH <urn:doid> {
    ?disease a obo:DOID_N ;
             rdfs:label ?diseaseLabel .
    FILTER (CONTAINS(LCASE(?diseaseLabel), "infectious"))
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
PREFIX obo: <http://purl.obolibrary.org/obo/>

SELECT ?doid_label ?hpoa_label WHERE {
  GRAPH <urn:doid> {
    ?disease oboInOwl:hasDbXref ?omim ;
             rdfs:label ?doid_label .
    FILTER(STRSTARTS(STR(?omim), "MIM:"))
  }

  GRAPH <urn:hpoa> {
    ?phenotype hpoa:source_id ?hpoa_id;
                 hpoa:has_phenotype ?disease ;
                 rdfs:label ?hpoa_label .
    FILTER(CONTAINS(STR(?hpoa_label), "...") )
  }

  ?disease a oboInOwl:Disease ;
           oboInOwl:hasDbXref ?omim .
  ?phenotype a hpoa:Phenotype;
              hpoa:has_phenotype ?disease.

  FILTER (?doid_label != ?hpoa_label)
}
LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
PREFIX doid: <urn:doid>
PREFIX hpo: <urn:hpo>

SELECT ?phenotype_label WHERE {
  GRAPH <doid> {
    ?cfId oboInOwl:hasDbXref "MIM:219700" ;
          rdfs:label ?doid_label .
  }
  GRAPH <hpoa> {
    ?phenotype hpoa:source_id BIND(REPLACE(STR(?doid_label), "^MIM:", "OMIM:") ) ;
                hpoa:has_phenotype ?cfId ;
                rdfs:label ?phenotype_label .
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT DISTINCT ?disease_name WHERE {
  GRAPH <urn:hpoa> {
    ?disease rdfs:label ?disease_name .
    FILTER(CONTAINS(LCASE(?disease_name), "syndrome"))
  }
} LIMIT 20

PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT ?subclass ?label WHERE {
  GRAPH <urn:doid> {
    ?subclass a owl:Class ;
              rdfs:label ?label .
    ?subclass rdfs:subClassOf obo:DOID_5614 .
  }
} LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
SELECT ?label (COUNT(DISTINCT ?xref) AS ?num_xrefs) WHERE {
  GRAPH <urn:doid> {
    ?disease oboInOwl:hasDbXref ?xref ;
             rdfs:label ?label .
  }
} GROUP BY ?disease ?label ORDER BY DESC(?num_xrefs) LIMIT 10

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT ?disease_name (COUNT(DISTINCT ?pheno) AS ?num_phenotypes) WHERE {
  GRAPH <urn:doid> {
    ?doid_class rdfs:subClassOf+ obo:DOID_630 .
    ?doid_class oboInOwl:hasDbXref ?xref .
    FILTER(STRSTARTS(STR(?xref), "MIM:"))
  }
  BIND(REPLACE(STR(?xref), "^MIM:", "OMIM:") AS ?omim_id)
  GRAPH <urn:hpoa> {
    ?disease hpoa:source_id ?omim_id ;
             hpoa:has_phenotype ?pheno ;
             rdfs:label ?disease_name .
  }
} GROUP BY ?disease_name
HAVING (COUNT(DISTINCT ?pheno) > 10)
ORDER BY DESC(?num_phenotypes)
LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT ?phenotype_label (COUNT(DISTINCT ?disease) AS ?frequency) WHERE {
  GRAPH <urn:hpoa> {
    ?disease hpoa:has_phenotype ?pheno .
  }
  GRAPH <urn:hpo> {
    ?pheno rdfs:label ?phenotype_label .
  }
} GROUP BY ?phenotype_label
ORDER BY DESC(?frequency)
LIMIT 10

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>

SELECT ?other_name (COUNT(DISTINCT ?pheno) AS ?shared) WHERE {
  GRAPH <urn:hpoa> {
    ?disease hpoa:source_id "OMIM:154700" ;
            hpoa:has_phenotype ?pheno .
    ?other hpoa:has_phenotype ?pheno ;
           rdfs:label ?other_name .
    FILTER(CONTAINS(LCASE(?other_name), "marfan"))
    FILTER (?other != ?disease)
  }
} GROUP BY ?other_name
HAVING (COUNT(DISTINCT ?pheno) >= 3)
ORDER BY DESC(?shared)
LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
SELECT ?child ?child_label ?parent ?parent_label WHERE {
  GRAPH <urn:doid> {
    ?child rdfs:subClassOf+ obo:DOID_0050700 ;
           rdfs:label ?child_label .
    ?child rdfs:subClassOf ?parent .
    ?parent rdfs:label ?parent_label .
  }
} LIMIT 30

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT DISTINCT ?phenotype_label WHERE {
  GRAPH <urn:doid> {
    ?marfan rdf:type obo:DOID ;
             rdfs:label "Marfan syndrome" .
  }
  GRAPH <urn:hpoa> {
    ?pheno hpoa:source_id "MIM:154700" ;
            hpoa:has_phenotype ?disease ;
            rdfs:label ?phenotype_label .
    ?eds hpoa:source_id "OMIM:130000" ;
         hpoa:has_phenotype ?disease2 ;
         rdfs:label ?phenotype_label2 .
  }
  FILTER (CONTAINS(LCASE(?phenotype_label), "marfan"))
  MINUS {
    FILTER (CONTAINS(LCASE(?phenotype_label2), "ehlers-danlos"))
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT ?doid_label WHERE {
  GRAPH <urn:doid> {
    ?disease rdfs:subClassOf obo:DOID_4 ;
             rdfs:label ?doid_label ;
             oboInOwl:hasDbXref ?xref .
    FILTER(STRSTARTS(STR(?xref), "MIM:"))
  }
  OPTIONAL {
    GRAPH <urn:hpoa> {
      ?hpoa_disease hpoa:source_id ?xref .
    }
  }
  FILTER(!BOUND(?hpoa_disease))
} LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX hpoa: <http://example.org/hpoa/>
PREFIX urn:doid: <urn:doid>
PREFIX urn:hpo: <urn:hpo>
PREFIX urn:hpoa: <urn:hpoa>

SELECT ?phenotype_label ?disease_name WHERE {
  GRAPH urn:hpo {
    ?pheno rdfs:label ?phenotype_label .
    FILTER(CONTAINS(LCASE(?phenotype_label), "cardiac"))
  }
  GRAPH urn:hpoa {
    ?disease hpoa:source_id ?pheno ;
             rdfs:label ?disease_name.
    BIND(REPLACE(STR(?mim), "^MIM:", "OMIM:") AS ?omim)
    FILTER (?omim = "OMIM0001626")
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT DISTINCT ?ancestor_label WHERE {
  GRAPH <urn:doid> {
    <http://purl.obolibrary.org/obo/DOID_2841> rdfs:subClassOf+ ?ancestor .
    ?ancestor rdfs:label ?ancestor_label .
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT ?category_label (COUNT(DISTINCT ?pheno) AS ?count) WHERE {
  GRAPH <urn:hpoa> {
    ?disease hpoa:has_phenotype ?pheno .
  }
  GRAPH <urn:hpo> {
    ?pheno rdfs:subClassOf+ ?category .
    ?category rdfs:subClassOf obo:HP_0000118 .
    ?category rdfs:label ?category_label .
  }
} GROUP BY ?category ?category_label
ORDER BY DESC(?count)

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT DISTINCT ?doid_label ?hpoa_label WHERE {
  GRAPH <urn:doid> {
    ?disease rdfs:subClassOf+ obo:DOID_0003769 ;
             rdfs:label ?doid_label .
  }
  GRAPH <urn:hpoa> {
    ?hpoa hpoa:source_id ?doid_id ;
          rdfs:label ?hpoa_label .
    FILTER(CONTAINS(LCASE(?hpoa_label), "metabolic"))
  }
  ?disease oboInOwl:hasDbXref ?doid_xref .
  ?hpoa hpoa:has_phenotype ?doid_phenotype .
  FILTER (?doid_xref = "MIM:")
  FILTER (?doid_phenotype = "metabolic disease")
} LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>

SELECT ?doidLabel ?hpoaLabel WHERE {
  # DOID query
  GRAPH <urn:doid> {
    ?disease a oboInOwl:Class ;
             rdfs:label ?doidLabel .
    FILTER(CONTAINS(LCASE(?doidLabel), "disease"))
    FILTER NOT EXISTS {
      ?disease oboInOwl:hasOBONamespace "" .
    }
  }

  UNION

  # HPOA query
  GRAPH <urn:hpoa> {
    ?phenotype a hpoa:Disease ;
               rdfs:label ?hpoaLabel .
    FILTER(CONTAINS(LCASE(?hpoaLabel), "disease"))
  }
}
LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
SELECT ?label ?synonym WHERE {
  GRAPH <urn:doid> {
    ?disease rdfs:subClassOf obo:DOID_863 ;
             rdfs:label ?label .
    OPTIONAL {
      ?disease oboInOwl:hasExactSynonym ?synonym .
    }
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT DISTINCT ?source_id ?disease_name WHERE {
  GRAPH <urn:hpoa> {
    ?disease hpoa:source_id ?source_id ;
             rdfs:label ?disease_name .
    FILTER(STRSTARTS(?source_id, "OMIM:"))
  }
  BIND(REPLACE(STR(?source_id), "^OMIM:", "MIM:") AS ?mim_id)
  OPTIONAL {
    GRAPH <urn:doid> {
      ?doid_class oboInOwl:hasDbXref ?mim_id .
    }
  }
  FILTER(!BOUND(?doid_class))
} LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
PREFIX doid: <urn:doid>
PREFIX hpo: <urn:hpo>

SELECT ?phenotype WHERE {
  GRAPH <urn:hpo> {
    ?phenotype rdfs:label ?l .
    FILTER(CONTAINS(LCASE(?l), "eye"))
    OPTIONAL {
      ?phenotype oboInOwl:hasDbXref ?xref .
      FILTER(STRSTARTS(STR(?xref), "OMIM:"))
      BIND(REPLACE(STR(?xref), "^OMIM:", "MIM:") AS ?mim)
    }
  }
  GRAPH <urn:hpoa> {
    ?phenotype hpoa:has_phenotype ?hp .
    OPTIONAL {
      ?hp hpoa:source_id ?source .
    }
  }
}
LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT ?doid_label ?hpo_label WHERE {
  GRAPH <urn:doid> {
    obo:DOID_2841 rdfs:label ?doid_label .
  }
  GRAPH <urn:hpo> {
    ?term rdfs:label ?hpo_label .
    FILTER(LCASE(?hpo_label) = "asthma")
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?term ?label WHERE {
  {
    GRAPH <urn:doid> {
      ?term rdfs:label ?label .
      FILTER(CONTAINS(LCASE(?label), "epilepsy"))
    }
  }
  UNION
  {
    GRAPH <urn:hpo> {
      ?term rdfs:label ?label .
      FILTER(CONTAINS(LCASE(?label), "epilepsy"))
    }
  }
} LIMIT 30

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT ?doidLabel ?synonymLabel WHERE {
  GRAPH <urn:doid> {
    ?disease a obo:DOID_N ;
             rdfs:label ?doidLabel .
    OPTIONAL {
      ?disease oboInOwl:hasExactSynonym ?synonym ;
              oboInOwl:id ?synonymLabel .
    }
  }
  FILTER (LCASE(?doidLabel) CONTAINS ("parkinson disease"))
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT DISTINCT ?disease_name ?category WHERE {
  GRAPH <urn:hpoa> {
    ?disease hpoa:has_phenotype ?pheno ;
             rdfs:label ?disease_name .
  }
  {
    GRAPH <urn:hpo> {
      ?pheno rdfs:subClassOf+ obo:HP_0000707 .
    }
    BIND("nervous system" AS ?category)
  }
  UNION
  {
    GRAPH <urn:hpo> {
      ?pheno rdfs:subClassOf+ obo:HP_0001626 .
    }
    BIND("cardiovascular" AS ?category)
  }
} LIMIT 30

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX hpoa: <http://example.org/hpoa/>

SELECT ?disease_name ?cnt WHERE {
  GRAPH <urn:hpoa> {
    ?disease hpoa:has_phenotype ?pheno ;
             rdfs:label ?disease_name .
  }
  GROUP BY ?disease ?disease_name
  HAVING COUNT(?pheno) > (SELECT AVG(cnt) FROM { GRAPH <urn:hpoa> {?d hpoa:has_phenotype ?p; rdfs:label ?cnt}})
} ORDER BY DESC(?cnt) LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT ?phenotype_label (COUNT(DISTINCT ?disease) AS ?freq) WHERE {
  {
    GRAPH <urn:doid> {
      ?doid_class rdfs:subClassOf+ obo:DOID_417 ;
                    oboInOwl:hasDbXref ?xref .
      FILTER(STRSTARTS(STR(?xref), "MIM:"))
    }
  }
  GRAPH <urn:hpoa> {
    ?disease hpoa:source_id ?omim_id ;
             hpoa:has_phenotype ?pheno .
  }
  GRAPH <urn:hpo> {
    ?pheno rdfs:label ?phenotype_label .
  }
