PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>

GRAPH <urn:doid> {
  # Find DOID for Asthma and COPD (using labels)
  ?disease1 obo:DOID_N a obo:DOID_N ;
           rdfs:label "asthma" .
  ?disease2 obo:DOID_N a obo:DOID_N ;
           rdfs:label "COPD" .

  # Find ancestors of Asthma and COPD
  ?ancestor1 a obo:DOID_N ;
             rdfs:subClassOf+ ?disease1;
             rdfs:label ?ancestorLabel .
  ?ancestor2 a obo:DOID_N ;
             rdfs:subClassOf+ ?disease2;
             rdfs:label ?ancestorLabel .

}

GRAPH <urn:hpo> {
    # Find HPO for Asthma and COPD (using labels)
    ?phenotype1 obo:HP_N a obo:HP_N ;
                 rdfs:label "asthma" .
    ?phenotype2 obo:HP_N a obo:HP_N ;
                 rdfs:label "COPD" .

    # Find ancestors of Asthma and COPD
    ?ancestor1 a obo:HP_N ;
             rdfs:subClassOf+ ?phenotype1;
             rdfs:label ?ancestorLabel .
    ?ancestor2 a obo:HP_N ;
             rdfs:subClassOf+ ?phenotype2;
             rdfs:label ?ancestorLabel .

}


SELECT DISTINCT ?ancestorLabel WHERE {
  ?ancestor1 a obo:DOID_N ;
           rdfs:subClassOf+ ?disease1;
           rdfs:label ?ancestorLabel.
  ?ancestor2 a obo:HP_N ;
