    ?disease a obo:DOID_N ;
             rdfs:label ?doidLabel .
    FILTER(CONTAINS(LCASE(?doidLabel), "eye"))
  }

  GRAPH <urn:hpoa> {
    ?phenotype a hpoa:Phenotype ;
                hpoa:source_id ?doidId ;
                rdfs:label ?hpoaLabel .
    FILTER(CONTAINS(LCASE(?hpoaLabel), "eye"))
  }

  # Cross-graph normalization
  OPTIONAL {
    ?doid a obo:DOID_N ;
          oboInOwl:hasDbXref ?xref .
    ?xref rdfs:label "MIM:"^ ?mim .
    BIND(REPLACE(STR(?mim), "^MIM:", "OMIM:") AS ?omim)
  }

  # Linking DOID to HPOA based on OMIM
  OPTIONAL {
    ?doid a obo:DOID_N ;
          hpoa:source_id ?hpoaId .
  }
}

